// ─── PARSER MULTI-FUENTE v3 ───────────────────────────
// Fuentes:
// [0] ABC Color Economia (HTML)
// [1] ABC Color Nacionales (HTML)
// [2] Google News RSS - Tributos Paraguay
// [3] Google News RSS - Contadores DNIT
// [4] Google News RSS - SIFEN Factura

const items = $input.all();
const abcEconHtml = items[0]?.json?.data || items[0]?.json?.body || '';
const abcNacHtml  = items[1]?.json?.data || items[1]?.json?.body || '';
const gnewsTrib   = items[2]?.json?.data || items[2]?.json?.body || '';
const gnewsCont   = items[3]?.json?.data || items[3]?.json?.body || '';
const gnewsSifen  = items[4]?.json?.data || items[4]?.json?.body || '';

const noticias = [];

function cleanText(s) {
  return (s || '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>').replace(/&#\d+;/g, '').replace(/\s+/g, ' ').trim();
}

function dateFromUrl(url) {
  const m = url.match(/(\d{4})\/(\d{2})\/(\d{2})/);
  if (m) return m[3] + '/' + m[2] + '/' + m[1];
  return new Date().toLocaleDateString('es-PY');
}

// ══ Parser ABC Color (HTML) ══
function parseABC(html, section) {
  try {
    const titleRx = /aria-label="Enlace a comentarios para el art[ií]culo ([^"]+)"/gi;
    const titles = [];
    let tm;
    while ((tm = titleRx.exec(html)) !== null) titles.push(tm[1].trim());

    const urlRx = new RegExp('href="(/' + section + '/\\d{4}/\\d{2}/\\d{2}/[^"]+/)"', 'gi');
    const urlSet = new Set();
    const urls = [];
    let um;
    while ((um = urlRx.exec(html)) !== null) {
      if (!um[1].includes('#') && !urlSet.has(um[1])) {
        urlSet.add(um[1]);
        urls.push(um[1]);
      }
    }

    const introRx = /class="article-intro"><p>([^<]+)<\/p>/gi;
    const intros = [];
    let im;
    while ((im = introRx.exec(html)) !== null) intros.push(cleanText(im[1]).slice(0, 250));

    const count = Math.min(titles.length, urls.length);
    for (let i = 0; i < count; i++) {
      noticias.push({
        title: titles[i].slice(0, 200),
        url: 'https://www.abc.com.py' + urls[i],
        source: 'ABC Color',
        category: section === 'economia' ? 'fiscal' : 'dnit',
        date: dateFromUrl(urls[i]),
        summary: intros[i] || ''
      });
    }
  } catch(e) {}
}

// ══ Parser Google News RSS (XML) ══
function parseGoogleRSS(xml, defaultCategory) {
  try {
    const itemRx = /<item>[\s\S]*?<\/item>/gi;
    let match;
    while ((match = itemRx.exec(xml)) !== null) {
      const block = match[0];

      const titleM = block.match(/<title>([^<]+)<\/title>/);
      const linkM  = block.match(/<link>([^<]+)<\/link>/);
      const dateM  = block.match(/<pubDate>([^<]+)<\/pubDate>/);
      const srcM   = block.match(/<source[^>]*>([^<]+)<\/source>/);

      if (!titleM) continue;

      // Google News title format: "Titulo - Fuente"
      let rawTitle = cleanText(titleM[1]);
      let source = srcM ? cleanText(srcM[1]) : '';

      // Remover " - Fuente" del final del título si está duplicado
      if (source && rawTitle.endsWith(' - ' + source)) {
        rawTitle = rawTitle.slice(0, -(source.length + 3));
      }

      // Formatear fecha
      let dateStr = '';
      if (dateM) {
        try {
          const d = new Date(dateM[1]);
          dateStr = d.toLocaleDateString('es-PY', { day: '2-digit', month: '2-digit', year: 'numeric' });
        } catch(e) { dateStr = dateM[1]; }
      }

      // Categorizar por contenido
      let category = defaultCategory;
      const lower = rawTitle.toLowerCase();
      if (lower.includes('dnit') || lower.includes('set') || lower.includes('contribuyente')) category = 'dnit';
      if (lower.includes('sifen') || lower.includes('factura electr')) category = 'sifen';

      noticias.push({
        title: rawTitle.slice(0, 200),
        url: linkM ? linkM[1] : '',
        source: source || 'Google News',
        category,
        date: dateStr,
        summary: ''
      });
    }
  } catch(e) {}
}

// ── Ejecutar parsers ──
parseABC(abcEconHtml, 'economia');
parseABC(abcNacHtml, 'nacionales');
parseGoogleRSS(gnewsTrib, 'fiscal');
parseGoogleRSS(gnewsCont, 'dnit');
parseGoogleRSS(gnewsSifen, 'sifen');

// ── Deduplicar por título ──
const unique = [];
const seen = new Set();
for (const n of noticias) {
  const key = n.title.toLowerCase().replace(/[^a-záéíóúñ0-9]/g, '').slice(0, 50);
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(n);
}

const result = unique.slice(0, 30);

return [{
  json: {
    noticias: result,
    lastUpdated: new Date().toISOString(),
    count: result.length,
    sources: ['ABC Color Economia', 'ABC Color Nacionales', 'Google News (tributos)', 'Google News (contadores)', 'Google News (SIFEN)']
  }
}];
